  ('disabled-7fec267e-moex-00130', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '審議式民主主張公共政策的審議過程必須符合的基本原則中，下列何者不屬 之？', '["公開性（publicity）", "競爭性（competition）", "課責性（accountability）", "平等性（equity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
