  ('disabled-7fec267e-moex-00134', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '關於大法庭制度之敘述，下列何者正確？', '["由司法院大法官組成大法庭，統一各法院之法律見解", "大法庭裁定，具有通案效力，拘束各審級法院", "最高法院先前依法選編之判例視為大法庭之裁判", "最高行政法院各庭審理案件，經評議後認採為裁判基礎之法律見解，與 先前裁判之法律見解歧異，應以裁定敘明理由，提案予大法庭裁判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
