  ('disabled-7fec267e-moex-00136', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '有關行政法上權利與義務之繼受，下列何者錯誤？', '["營利事業因合併而消滅，因合併前之應納稅捐無一身專屬性，應由合併 後存續事業繳納", "營利事業因合併而消滅，於合併前應退稅捐，該公法上請求權應由合併 後存續事業行使", "廢棄物清理義務非不得由第三人代法定義務人清理，故義務人得以私法 契約移轉第三人", "義務縱使不具一身專屬性，義務人仍須有法律上移轉權限，始得以公法 行為為有效移轉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00137', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3082b5f1', 'sub-disabled-7fec267e-05', NULL, 'single_choice', '關於我國地方自治之敘述，下列何者錯誤？', '["地方自治團體得以自治條例規範居民之權利義務，惟其內容仍不得違反 法律保留原則及比例原則", "依地方制度法規定，直轄市山地原住民區為地方自治團體", "依地方制度法規定，得以自治條例規定處以行政罰者，僅有直轄市或縣 （市），而不包含鄉（鎮、市）在內", "關於憲法未列舉事項究竟應屬中央或地方之權限產生爭議時，由行政院 解決之 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
